INSERT INTO `t_product` (`shop_id`, `category_id`, `brand_id`, `name`, `subtitle`, `description`, `main_image`, `price`, `original_price`, `stock`, `sales`, `view_count`, `favorite_count`, `review_count`, `avg_review_score`, `is_recommended`, `is_new`, `publish_time`, `status`, `created_by`, `updated_by`) VALUES
(1, 12, 2, 'iPhone 15 Pro', '钛金属设计，A17 Pro芯片，4800万像素主摄', '<p>Apple iPhone 15 Pro 采用钛金属设计，搭载 A17 Pro 芯片，配备 4800 万像素主摄像头。支持 USB-C 接口，动作按钮可自定义功能。</p>', '/images/products/digital_phone.jpg', 7999.00, 8999.00, 50, 120, 1266, 97, 44, 4.4, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(1, 12, 5, '华为 Mate 60 Pro', '麒麟9000S芯片，卫星通话，超可靠玄武架构', '<p>华为 Mate 60 Pro 搭载麒麟 9000S 芯片，支持卫星通话功能。超可靠玄武架构，第二代昆仑玻璃，十档可变光圈。</p>', '/images/products/digital_phone.jpg', 6999.00, 7999.00, 80, 200, 2409, 69, 83, 4.8, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(1, 12, 1, '小米14 Ultra', '徕卡光学全焦段四摄，骁龙8 Gen3，卫星通信', '<p>小米14 Ultra 配备徕卡光学全焦段四摄，搭载第三代骁龙8移动平台。支持双向卫星通信，5300mAh大电池。</p>', '/images/products/digital_phone.jpg', 6499.00, 6999.00, 100, 350, 4107, 284, 147, 4.7, 1, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(1, 12, 5, 'OPPO Find X7 Ultra', '双潜望四主摄，哈苏影像，潮汐架构', '<p>OPPO Find X7 Ultra 搭载双潜望四主摄系统，哈苏联合研发影像。潮汐架构提升能效，100W超级闪充。</p>', '/images/products/digital_phone.jpg', 5999.00, 6999.00, 60, 150, 913, 98, 43, 4.4, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(1, 12, 2, 'vivo X100 Pro', '蔡司APO超级长焦，天玑9300，蓝海电池', '<p>vivo X100 Pro 配备蔡司 APO 超级长焦镜头，搭载天玑 9300 旗舰芯片。蓝海电池技术，120W双芯闪充。</p>', '/images/products/digital_phone.jpg', 4999.00, 5499.00, 90, 280, 3862, 191, 95, 4.5, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(1, 13, 5, 'MacBook Air M3', '轻薄便携，M3芯片强劲性能，18小时续航', '<p>全新 MacBook Air 搭载 M3 芯片，轻薄设计，支持双屏显示。18小时电池续航，1080p FaceTime 高清摄像头。</p>', '/images/products/digital_laptop.jpg', 8999.00, 9999.00, 30, 80, 433, 72, 39, 4.7, 1, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(1, 13, 5, '华为MateBook X Pro', '微绒金属机身，3.1K原色屏，智慧办公', '<p>华为 MateBook X Pro 采用微绒金属机身，配备 3.1K 原色全面屏。支持超级终端，智慧办公体验升级。</p>', '/images/products/digital_laptop.jpg', 9999.00, 11999.00, 25, 60, 467, 34, 22, 4.6, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(1, 13, 2, '联想小新Pro 16', '13代酷睿i7，2.5K高刷屏，大电池长续航', '<p>联想小新 Pro 16 搭载第13代英特尔酷睿 i7 处理器，2.5K 120Hz 高刷屏。75Wh 大电池，支持快充。</p>', '/images/products/digital_laptop.jpg', 5499.00, 6499.00, 50, 180, 1961, 94, 51, 4.8, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(1, 13, 2, '戴尔XPS 15', '4K OLED触控屏，RTX 4060，创作者首选', '<p>戴尔 XPS 15 配备 4K OLED 触控显示屏，可选 RTX 4060 显卡。CNC 精雕机身，创作者移动工作站首选。</p>', '/images/products/digital_laptop.jpg', 14999.00, 16999.00, 15, 40, 463, 13, 10, 4.7, 1, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(1, 13, 2, '华硕天选5 Pro', '锐龙9处理器，RTX 4070，2.5K电竞屏', '<p>华硕天选5 Pro 搭载 AMD 锐龙 9 处理器，配备 RTX 4070 显卡。2.5K 165Hz 电竞屏，冰川散热架构。</p>', '/images/products/digital_laptop.jpg', 8999.00, 10499.00, 40, 120, 704, 49, 35, 4.4, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(1, 14, 5, 'AirPods Pro 2', '主动降噪，通透模式，空间音频', '<p>AirPods Pro 第二代配备 H2 芯片，主动降噪效果最高提升至 2 倍。支持自适应通透模式，单次充电聆听时间最长可达 6 小时。</p>', '/images/products/digital_earbuds.jpg', 1899.00, 2299.00, 100, 450, 5353, 241, 197, 4.6, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(1, 14, 2, '索尼WH-1000XM5', '行业领先降噪，30小时续航，舒适佩戴', '<p>索尼 WH-1000XM5 头戴式降噪耳机，配备两个处理器控制 8 个麦克风。30 小时超长续航，轻量化设计佩戴舒适。</p>', '/images/products/digital_earbuds.jpg', 2499.00, 2999.00, 60, 220, 1794, 107, 95, 4.3, 1, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(1, 14, 1, '华为FreeBuds Pro 3', '星闪连接，智慧动态降噪，无损音质', '<p>华为 FreeBuds Pro 3 支持星闪连接技术，智慧动态降噪 3.0。超感知原声双单元，支持 L2HC 无损音质传输。</p>', '/images/products/digital_earbuds.jpg', 1499.00, 1699.00, 80, 310, 3415, 283, 128, 4.7, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(1, 14, 5, 'JBL Pulse 5', '360度全彩灯光秀，40W大功率，IP67防水', '<p>JBL Pulse 5 音乐脉动五代，360度全彩灯光秀随音乐律动。40W 大功率输出，IP67 防尘防水，12小时续航。</p>', '/images/products/digital_earbuds.jpg', 1899.00, 2199.00, 45, 130, 814, 66, 56, 4.5, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(1, 14, 2, '小米Sound Pro', '哈曼调音，7单元声学，NFC一碰传音', '<p>小米 Sound Pro 高保真智能音箱，经哈曼卡顿专业调音。7单元声学架构，360度全向出音，支持 NFC 一碰传音。</p>', '/images/products/digital_earbuds.jpg', 999.00, 1299.00, 70, 190, 2639, 79, 91, 4.5, 1, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(2, 15, 6, '雅诗兰黛小棕瓶精华', '第七代特润修护肌活精华露，抗老修护', '<p>雅诗兰黛第七代小棕瓶精华，加速肌因修护，激活细胞新生。早晚使用，肌肤更紧致、更弹润、更透亮。</p>', '/images/products/beauty_serum.jpg', 850.00, 1080.00, 200, 350, 2755, 240, 151, 4.4, 1, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(2, 15, 4, 'SK-II神仙水', 'PITERA精华，改善肤质，晶莹剔透', '<p>SK-II 护肤精华露（神仙水），蕴含超过 90% PITERA 成分。帮助改善肤质，令肌肤晶莹剔透，焕发自然光彩。</p>', '/images/products/beauty_serum.jpg', 1540.00, 1890.00, 100, 180, 2256, 150, 55, 4.7, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(2, 15, 4, '兰蔻小黑瓶肌底液', '强维稳快修护，肌肤细腻透亮', '<p>兰蔻第二代小黑瓶肌底精华液， Bio-7 生物专研配方。强维稳快修护，7天肌肤细腻透亮，改善粗糙泛红。</p>', '/images/products/beauty_serum.jpg', 1080.00, 1280.00, 150, 260, 3560, 158, 80, 4.5, 0, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(2, 15, 3, '海蓝之谜修护精萃水', '神奇活性精萃，深层修护，焕活肌肤', '<p>海蓝之谜修护精萃水，蕴含神奇活性精萃 Mirackle Broth。深层修护焕活肌肤，质地如丝缎般柔滑。</p>', '/images/products/beauty_serum.jpg', 1290.00, 1520.00, 80, 140, 2066, 119, 69, 4.4, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(2, 15, 6, '欧莱雅复颜玻尿酸水乳套装', '玻尿酸补水，淡化细纹，紧致肌肤', '<p>欧莱雅复颜玻尿酸系列水乳套装，蕴含高纯度玻尿酸。深层补水保湿，淡化细纹，提拉紧致肌肤轮廓。</p>', '/images/products/beauty_serum.jpg', 399.00, 520.00, 300, 680, 6814, 485, 332, 4.8, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(2, 16, 4, '迪奥烈艳蓝金口红', '999经典正红，丝绒质地，显白不拔干', '<p>迪奥烈艳蓝金唇膏 999，经典正红色号。丝绒质地，显白不拔干，持久显色，一抹尽显高级妆感。</p>', '/images/products/beauty_lipstick.jpg', 380.00, 450.00, 300, 520, 6470, 316, 173, 4.6, 0, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(2, 16, 6, '兰蔻持妆粉底液', '24小时持妆，轻薄透气，遮瑕不假面', '<p>兰蔻持妆轻透粉底液，24小时持久不脱妆。轻薄透气配方，遮瑕不假面，适合各种肤质使用。</p>', '/images/products/beauty_lipstick.jpg', 420.00, 520.00, 150, 280, 1694, 109, 104, 4.7, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(2, 16, 3, 'YSL小金条口红', '哑光丝滑，高定香调，奢华质感', '<p>YSL 圣罗兰小金条细管口红，哑光丝滑质地。高定香调，奢华黑金质感外壳，多种热门色号可选。</p>', '/images/products/beauty_lipstick.jpg', 390.00, 460.00, 250, 420, 5075, 194, 164, 4.7, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(2, 16, 6, 'MAC魅可子弹头口红', '经典哑光，饱和显色，持久不脱妆', '<p>MAC 魅可经典子弹头口红，多种质地可选。饱和显色，持久不脱妆，Chili、Ruby Woo 等经典色号永不过时。</p>', '/images/products/beauty_lipstick.jpg', 180.00, 220.00, 400, 890, 7975, 446, 435, 4.5, 0, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(2, 16, 6, '完美日记动物眼影盘', '12色眼影，珠光哑光结合，新手友好', '<p>完美日记探险家十二色动物眼影盘，珠光哑光多种质地结合。粉质细腻不飞粉，新手也能轻松画出精致眼妆。</p>', '/images/products/beauty_lipstick.jpg', 129.00, 199.00, 500, 1200, 7377, 415, 407, 4.4, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(2, 17, 4, '施华蔻精油洗发水', '8种植物精油，修护受损发质，柔顺亮泽', '<p>施华蔻金致润养精油洗发水，蕴含 8 种珍贵植物精油。深入修护受损发质，洗后柔顺亮泽，持久留香。</p>', '/images/products/beauty_serum.jpg', 89.00, 129.00, 300, 650, 5541, 228, 191, 4.7, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(2, 17, 3, '欧舒丹樱花身体乳', '普罗旺斯樱花香，保湿滋润，轻盈不黏腻', '<p>欧舒丹甜蜜樱花身体乳，来自普罗旺斯的樱花香氛。乳木果油深层保湿，质地轻盈不黏腻，肌肤柔滑如丝。</p>', '/images/products/beauty_serum.jpg', 260.00, 320.00, 150, 340, 2523, 133, 131, 4.7, 0, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(2, 17, 4, '资生堂芬浓发膜', '美容液修护，改善干枯毛躁，一梳到底', '<p>资生堂芬浓 Premium Touch 发膜，蕴含 6 种美容液成分。改善干枯毛躁受损发质，洗后一梳到底，顺滑光泽。</p>', '/images/products/beauty_serum.jpg', 68.00, 98.00, 400, 920, 5042, 583, 230, 4.4, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(2, 17, 4, '佳洁士热感美白牙膏', 'Microheat微热技术，溶解牙渍，亮白牙齿', '<p>佳洁士 3D 炫白热感美白牙膏，创新 Microheat 微热技术。遇水发热溶解顽固牙渍，显著亮白牙齿。</p>', '/images/products/beauty_serum.jpg', 39.00, 59.00, 600, 1500, 20398, 577, 610, 4.5, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(2, 17, 6, '舒肤佳红石榴沐浴露', '排浊小气泡，深层清洁，清新果香', '<p>舒肤佳排浊红石榴沐浴露，微米级排浊小气泡技术。深层清洁毛孔，清新红石榴果香，洗后肌肤清爽不紧绷。</p>', '/images/products/beauty_serum.jpg', 45.00, 65.00, 500, 1100, 16184, 726, 466, 4.5, 0, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(3, 9, 14, '优衣库纯棉T恤', '100%新疆长绒棉，柔软亲肤，多色可选', '<p>优衣库经典圆领T恤，采用100%优质新疆长绒棉。触感柔软亲肤，透气吸汗，多色可选，百搭基础款。</p>', '/images/products/clothing_tshirt.jpg', 99.00, 129.00, 500, 1200, 15815, 1072, 538, 4.5, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(3, 9, 7, '杰克琼斯休闲衬衫', '牛津纺面料，修身剪裁，商务休闲两相宜', '<p>杰克琼斯男士休闲衬衫，采用经典牛津纺面料。修身剪裁版型，商务休闲两相宜，多色可选。</p>', '/images/products/clothing_tshirt.jpg', 299.00, 399.00, 200, 450, 2703, 206, 204, 4.7, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(3, 9, 9, '海澜之家休闲西裤', '弹力面料，免烫工艺，舒适有型', '<p>海澜之家男士休闲西裤，采用弹力混纺面料。免烫工艺易打理，修身版型舒适有型，商务通勤必备。</p>', '/images/products/clothing_tshirt.jpg', 199.00, 259.00, 300, 680, 8617, 300, 237, 4.6, 0, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(3, 9, 9, '太平鸟牛仔外套', '复古水洗，宽松版型，潮流百搭', '<p>太平鸟男士牛仔外套，经典复古水洗工艺。宽松版型潮流百搭，优质棉质面料，四季皆可穿着。</p>', '/images/products/clothing_tshirt.jpg', 459.00, 599.00, 120, 280, 2072, 122, 117, 4.4, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(3, 9, 7, '波司登轻薄羽绒服', '90%白鸭绒，轻薄保暖，便携收纳', '<p>波司登轻薄短款羽绒服，填充 90% 优质白鸭绒。轻薄保暖易收纳，防泼水面料，秋冬出行必备。</p>', '/images/products/clothing_tshirt.jpg', 399.00, 599.00, 180, 420, 5140, 145, 117, 4.5, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(3, 10, 7, 'ZARA碎花连衣裙', '法式浪漫碎花，收腰显瘦，夏日必备', '<p>ZARA 夏季新款碎花连衣裙，法式浪漫设计风格。收腰显瘦剪裁，轻盈透气面料，夏日出游必备单品。</p>', '/images/products/clothing_dress.jpg', 399.00, 499.00, 200, 450, 6599, 272, 122, 4.4, 0, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(3, 10, 7, 'ONLY针织开衫', '软糯亲肤，V领设计，温柔气质', '<p>ONLY 女士针织开衫，软糯亲肤面料。V领设计修饰脸型，温柔气质配色，春秋百搭单品。</p>', '/images/products/clothing_dress.jpg', 259.00, 349.00, 250, 560, 5469, 402, 245, 4.8, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(3, 10, 14, 'UR高腰阔腿裤', '垂坠面料，显瘦显高，通勤休闲', '<p>UR 女士高腰阔腿裤，垂坠感面料走路带风。高腰设计显瘦显高，黑色经典百搭，通勤休闲皆可。</p>', '/images/products/clothing_dress.jpg', 199.00, 279.00, 300, 720, 8600, 598, 204, 4.9, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(3, 10, 7, '韩都衣舍卫衣', 'oversize版型，加绒加厚，慵懒时尚', '<p>韩都衣舍秋冬加绒卫衣，oversize 宽松版型。内里加绒加厚保暖，慵懒时尚感，多色印花可选。</p>', '/images/products/clothing_dress.jpg', 159.00, 229.00, 400, 980, 8870, 964, 480, 4.8, 0, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(3, 10, 14, '茵曼棉麻衬衫', '天然棉麻，透气吸汗，文艺清新', '<p>茵曼女士棉麻衬衫，天然棉麻混纺面料。透气吸汗舒适，文艺清新设计，春夏穿着清爽自在。</p>', '/images/products/clothing_dress.jpg', 129.00, 189.00, 350, 820, 8264, 405, 234, 4.5, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
