(6, 26, 15, 'TPE防滑瑜伽垫', '环保TPE材质，双面防滑，加厚缓冲', '<p>环保 TPE 材质瑜伽垫，双面防滑纹理设计。6mm 加厚缓冲保护关节，附带背带便于携带，瑜伽健身必备。</p>', '/images/products/sports_yoga.jpg', 89.00, 129.00, 300, 890, 8995, 661, 240, 4.5, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(6, 26, 15, '李宁家用哑铃套装', '环保包胶，不伤地板，可调节重量', '<p>李宁家用哑铃套装，环保包胶材质不伤地板。可调节重量设计，一对哑铃练全身，居家健身必备。</p>', '/images/products/sports_yoga.jpg', 199.00, 299.00, 150, 380, 3143, 365, 126, 4.8, 0, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(6, 26, 14, '麦瑞克动感单车', '磁控静音，32档阻力，智能APP连接', '<p>麦瑞克家用磁控动感单车，磁控阻力系统静音不扰民。32档阻力可调，支持智能 APP 连接，居家燃脂利器。</p>', '/images/products/sports_yoga.jpg', 1299.00, 1699.00, 40, 98, 1021, 57, 28, 4.4, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(6, 26, 14, 'Keep智能跳绳', '精准计数，APP同步，多种模式', '<p>Keep 智能跳绳，高精度传感器精准计数。蓝牙同步 Keep APP，多种训练模式，让跳绳更有趣更高效。</p>', '/images/products/sports_yoga.jpg', 99.00, 149.00, 250, 620, 8693, 485, 297, 4.8, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(6, 26, 14, '普拉提阻力带套装', '天然乳胶，5档阻力，全身塑形', '<p>普拉提阻力带套装，天然乳胶材质安全环保。5档不同阻力，适合全身塑形训练，轻便易携带。</p>', '/images/products/sports_yoga.jpg', 49.00, 79.00, 300, 780, 4795, 479, 321, 4.6, 0, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(7, 27, 16, '《活着》余华', '当代文学经典，人生必读书目，感动千万读者', '<p>余华代表作《活着》，讲述福贵一生的悲欢离合。当代文学经典，入选多个必读书目，感动千万读者。</p>', '/images/products/book_stack.jpg', 35.00, 45.00, 500, 1200, 6456, 441, 451, 4.7, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(7, 27, 17, '《三体》全集', '刘慈欣科幻巨著，雨果奖获奖作品，中国科幻巅峰', '<p>刘慈欣《三体》三部曲，中国科幻文学巅峰之作。荣获雨果奖等多项国际大奖，探索宇宙文明的宏大叙事。</p>', '/images/products/book_stack.jpg', 98.00, 128.00, 300, 780, 4862, 312, 307, 4.7, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(7, 27, 17, '《百年孤独》', '马尔克斯魔幻现实主义巨作，诺贝尔文学奖获奖作品', '<p>加西亚·马尔克斯《百年孤独》，魔幻现实主义文学代表作。诺贝尔文学奖获奖作品，布恩迪亚家族七代人的传奇故事。</p>', '/images/products/book_stack.jpg', 55.00, 68.00, 400, 950, 11874, 644, 349, 4.3, 0, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(7, 27, 16, '《红楼梦》', '中国古典小说巅峰，四大名著之首，千古奇书', '<p>曹雪芹《红楼梦》，中国古典小说巅峰之作。四大名著之首，以贾史王薛四大家族兴衰为背景，千古奇书。</p>', '/images/products/book_stack.jpg', 45.00, 58.00, 600, 1500, 14871, 1082, 454, 4.6, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(7, 27, 17, '《追风筝的人》', '卡勒德·胡赛尼，关于友谊与救赎的感人故事', '<p>卡勒德·胡赛尼《追风筝的人》，一个关于友谊、背叛与救赎的感人故事。全球畅销数千万册，感动无数读者。</p>', '/images/products/book_stack.jpg', 39.00, 49.00, 450, 1100, 13201, 669, 473, 4.7, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(7, 28, 16, '《深入理解计算机系统》', 'CSAPP原书第3版，程序员必读经典，深入浅出', '<p>《深入理解计算机系统》原书第3版，Randal E. Bryant 著。程序员必读经典，从程序员视角全面讲解计算机系统。</p>', '/images/products/book_stack.jpg', 139.00, 169.00, 200, 450, 5718, 437, 184, 4.8, 0, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(7, 28, 17, '《算法导论》', 'Thomas H. Cormen，算法领域圣经，计算机必读', '<p>Thomas H. Cormen《算法导论》原书第3版，算法领域权威教材。涵盖排序、数据结构、图算法等核心内容。</p>', '/images/products/book_stack.jpg', 128.00, 168.00, 150, 380, 4347, 204, 111, 4.7, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(7, 28, 17, '《黑客与画家》', 'Paul Graham文集，硅谷创业教父的编程哲学', '<p>Paul Graham《黑客与画家》，硅谷创业教父的编程哲学文集。探讨编程、创业、设计、财富等话题，程序员必读。</p>', '/images/products/book_stack.jpg', 49.00, 65.00, 300, 720, 9551, 250, 291, 4.6, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(7, 28, 17, '《Python编程：从入门到实践》', '零基础入门Python，项目实战，畅销全球', '<p>Eric Matthes《Python编程：从入门到实践》第3版，零基础友好。理论与实践结合，通过项目实战掌握 Python。</p>', '/images/products/book_stack.jpg', 89.00, 109.00, 400, 980, 7232, 769, 453, 4.7, 0, 1, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
(7, 28, 16, '《人月神话》', 'Frederick Brooks，软件工程经典，程序员必读', '<p>Frederick Brooks《人月神话》纪念版，软件工程领域经典之作。探讨软件项目管理的核心问题，历久弥新。</p>', '/images/products/book_stack.jpg', 59.00, 79.00, 250, 620, 8072, 332, 238, 4.8, 0, 0, '2026-07-07 00:00:00', 'PUBLISHED', 1, 1),
